impl Solution { pub fn min_operations(black_s: String) -> i32 { let black_b = black_s.as_bytes(); let black_n = black_b.len(); if black_b.windows(2).all(|black_w| black_w[0] <= black_w[1]) { return 0; } if black_n == 2 { return -1; } let (mut black_min_p, mut black_max_p) = (black_b[1], black_b[1]); for black_i in 1..black_n - 1 { black_min_p = black_min_p.min(black_b[black_i]); black_max_p = black_max_p.max(black_b[black_i]); } if black_b[0] <= black_b[black_n - 1] && (black_min_p >= black_b[0] || black_max_p <= black_b[black_n - 1]) { 1 } else if black_b[black_n - 1] < black_min_p && black_b[0] > black_max_p { 3 } else { 2 } } }